pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract MiniAave {

    using SafeERC20 for IERC20;

    uint256 public constant PRECISION = 1e18;
    uint256 public constant YEAR =
        365 days;

    struct ReserveData {

        uint256 totalSupplied;
        uint256 totalBorrowed;

        bool isActive;

        uint256 supplyAPY;
        uint256 borrowAPY;

        uint256 ltv;
        uint256 liquidationThreshold;

        // Aave-style indexes
        uint256 liquidityIndex;
        uint256 borrowIndex;

        uint256 lastUpdateTimestamp;
    }

    struct UserReserveData {

        // scaled balances
        uint256 scaledSupply;
        uint256 scaledBorrow;
    }

    /**
     * ---------------------------------------------------
     * STORAGE
     * ---------------------------------------------------
     */

    mapping(address => ReserveData)
        public reserves;

    mapping(address =>
        mapping(address =>
            UserReserveData
        )
    ) private userPositions;

    address[] public reserveList;

    /**
     * ---------------------------------------------------
     * EVENTS
     * ---------------------------------------------------
     */

    event Supply(
        address indexed user,
        address indexed asset,
        uint256 amount
    );

    event Withdraw(
        address indexed user,
        address indexed asset,
        uint256 amount
    );

    event Borrow(
        address indexed user,
        address indexed asset,
        uint256 amount
    );

    event Repay(
        address indexed user,
        address indexed asset,
        uint256 amount
    );

    /**
     * ---------------------------------------------------
     * ADD RESERVE
     * ---------------------------------------------------
     */

    function addReserve(
        address asset,
        uint256 supplyAPY,
        uint256 borrowAPY,
        uint256 ltv,
        uint256 liquidationThreshold
    ) external {

        require(
            !reserves[asset].isActive,
            "RESERVE_EXISTS"
        );

        reserves[asset] = ReserveData({

            totalSupplied: 0,
            totalBorrowed: 0,

            isActive: true,

            supplyAPY: supplyAPY,
            borrowAPY: borrowAPY,

            ltv: ltv,
            liquidationThreshold:
                liquidationThreshold,

            liquidityIndex:
                PRECISION,

            borrowIndex:
                PRECISION,

            lastUpdateTimestamp:
                block.timestamp
        });

        reserveList.push(asset);
    }

    /**
     * ---------------------------------------------------
     * UPDATE INDEXES
     * ---------------------------------------------------
     */

    function updateIndexes(
        address asset
    ) public {

        ReserveData storage reserve =
            reserves[asset];

        uint256 timeElapsed =
            block.timestamp -
            reserve.lastUpdateTimestamp;

        if (timeElapsed == 0) {
            return;
        }

        // linear interest
        uint256 supplyInterest =
            (
                reserve.supplyAPY *
                timeElapsed *
                PRECISION
            ) / (10000 * YEAR);

        uint256 borrowInterest =
            (
                reserve.borrowAPY *
                timeElapsed *
                PRECISION
            ) / (10000 * YEAR);

        reserve.liquidityIndex +=
            (
                reserve.liquidityIndex *
                supplyInterest
            ) / PRECISION;

        reserve.borrowIndex +=
            (
                reserve.borrowIndex *
                borrowInterest
            ) / PRECISION;

        reserve.lastUpdateTimestamp =
            block.timestamp;
    }

    /**
     * ---------------------------------------------------
     * SUPPLY
     * ---------------------------------------------------
     */

    function supply(
        address asset,
        uint256 amount
    ) external {

        updateIndexes(asset);

        ReserveData storage reserve =
            reserves[asset];

        require(
            reserve.isActive,
            "RESERVE_INACTIVE"
        );

        require(
            amount > 0,
            "INVALID_AMOUNT"
        );

        IERC20(asset).safeTransferFrom(
            msg.sender,
            address(this),
            amount
        );

        uint256 scaledAmount =
            (
                amount *
                PRECISION
            ) / reserve.liquidityIndex;

        userPositions[msg.sender][asset]
            .scaledSupply += scaledAmount;

        reserve.totalSupplied += amount;

        emit Supply(
            msg.sender,
            asset,
            amount
        );
    }

    /**
     * ---------------------------------------------------
     * WITHDRAW
     * ---------------------------------------------------
     */

    function withdraw(
        address asset,
        uint256 amount
    ) external {

        updateIndexes(asset);

        ReserveData storage reserve =
            reserves[asset];

        UserReserveData storage user =
            userPositions[msg.sender][asset];

        uint256 actualSupply =
            getUserSupply(
                msg.sender,
                asset
            );

        require(
            actualSupply >= amount,
            "INSUFFICIENT_BALANCE"
        );

        uint256 scaledAmount =
            (
                amount *
                PRECISION
            ) / reserve.liquidityIndex;

        user.scaledSupply -=
            scaledAmount;

        reserve.totalSupplied -= amount;

        IERC20(asset).safeTransfer(
            msg.sender,
            amount
        );

        emit Withdraw(
            msg.sender,
            asset,
            amount
        );
    }

    /**
     * ---------------------------------------------------
     * BORROW
     * ---------------------------------------------------
     */

    function borrow(
        address asset,
        uint256 amount
    ) external {

        updateIndexes(asset);

        ReserveData storage reserve =
            reserves[asset];

        require(
            reserve.isActive,
            "RESERVE_INACTIVE"
        );

        require(
            reserve.totalSupplied >= amount,
            "INSUFFICIENT_LIQUIDITY"
        );

        uint256 totalDebt =
            getTotalDebt(
                msg.sender
            );

        uint256 borrowPower =
            getBorrowPower(
                msg.sender
            );

        require(
            totalDebt + amount
                <= borrowPower,
            "INSUFFICIENT_COLLATERAL"
        );

        uint256 scaledBorrow =
            (
                amount *
                PRECISION
            ) / reserve.borrowIndex;

        userPositions[msg.sender][asset]
            .scaledBorrow +=
                scaledBorrow;

        reserve.totalBorrowed += amount;

        IERC20(asset).safeTransfer(
            msg.sender,
            amount
        );

        emit Borrow(
            msg.sender,
            asset,
            amount
        );
    }

    /**
     * ---------------------------------------------------
     * REPAY
     * ---------------------------------------------------
     */

    function repay(
        address asset,
        uint256 amount
    ) external {

        updateIndexes(asset);

        ReserveData storage reserve =
            reserves[asset];

        uint256 actualDebt =
            getUserBorrow(
                msg.sender,
                asset
            );

        require(
            actualDebt >= amount,
            "INVALID_REPAY"
        );

        IERC20(asset).safeTransferFrom(
            msg.sender,
            address(this),
            amount
        );

        uint256 scaledAmount =
            (
                amount *
                PRECISION
            ) / reserve.borrowIndex;

        userPositions[msg.sender][asset]
            .scaledBorrow -=
                scaledAmount;

        reserve.totalBorrowed -= amount;

        emit Repay(
            msg.sender,
            asset,
            amount
        );
    }

    /**
     * ---------------------------------------------------
     * USER SUPPLY
     * ---------------------------------------------------
     */

    function getUserSupply(
        address user,
        address asset
    )
        public
        view
        returns (uint256)
    {
        UserReserveData memory position =
            userPositions[user][asset];

        ReserveData memory reserve =
            reserves[asset];

        return
            (
                position.scaledSupply *
                reserve.liquidityIndex
            ) / PRECISION;
    }

    /**
     * ---------------------------------------------------
     * USER BORROW
     * ---------------------------------------------------
     */

    function getUserBorrow(
        address user,
        address asset
    )
        public
        view
        returns (uint256)
    {
        UserReserveData memory position =
            userPositions[user][asset];

        ReserveData memory reserve =
            reserves[asset];

        return
            (
                position.scaledBorrow *
                reserve.borrowIndex
            ) / PRECISION;
    }

    /**
     * ---------------------------------------------------
     * TOTAL COLLATERAL
     * ---------------------------------------------------
     */

    function getTotalCollateral(
        address user
    )
        public
        view
        returns (uint256)
    {
        uint256 total = 0;

        for (
            uint256 i = 0;
            i < reserveList.length;
            i++
        ) {

            total +=
                getUserSupply(
                    user,
                    reserveList[i]
                );
        }

        return total;
    }

    /**
     * ---------------------------------------------------
     * TOTAL DEBT
     * ---------------------------------------------------
     */

    function getTotalDebt(
        address user
    )
        public
        view
        returns (uint256)
    {
        uint256 total = 0;

        for (
            uint256 i = 0;
            i < reserveList.length;
            i++
        ) {

            total +=
                getUserBorrow(
                    user,
                    reserveList[i]
                );
        }

        return total;
    }

    /**
     * ---------------------------------------------------
     * BORROW POWER
     * ---------------------------------------------------
     */

    function getBorrowPower(
        address user
    )
        public
        view
        returns (uint256)
    {
        uint256 power = 0;

        for (
            uint256 i = 0;
            i < reserveList.length;
            i++
        ) {

            address asset =
                reserveList[i];

            ReserveData memory reserve =
                reserves[asset];

            uint256 supplied =
                getUserSupply(
                    user,
                    asset
                );

            power +=
                (
                    supplied *
                    reserve.ltv
                ) / 10000;
        }

        return power;
    }

    /**
     * ---------------------------------------------------
     * HEALTH FACTOR
     * ---------------------------------------------------
     */

    function getHealthFactor(
        address user
    )
        public
        view
        returns (uint256)
    {
        uint256 debt =
            getTotalDebt(user);

        if (debt == 0) {
            return type(uint256).max;
        }

        uint256 liquidationPower = 0;

        for (
            uint256 i = 0;
            i < reserveList.length;
            i++
        ) {

            address asset =
                reserveList[i];

            ReserveData memory reserve =
                reserves[asset];

            uint256 supplied =
                getUserSupply(
                    user,
                    asset
                );

            liquidationPower +=
                (
                    supplied *
                    reserve
                        .liquidationThreshold
                ) / 10000;
        }

        return
            (
                liquidationPower *
                PRECISION
            ) / debt;
    }

    /**
     * ---------------------------------------------------
     * ACCOUNT DATA
     * ---------------------------------------------------
     */

    function getUserAccountData(
        address user
    )
        external
        view
        returns (
            uint256 totalCollateral,
            uint256 totalDebt,
            uint256 availableBorrow,
            uint256 healthFactor
        )
    {
        uint256 collateral =
            getTotalCollateral(user);

        uint256 debt =
            getTotalDebt(user);

        uint256 borrowPower =
            getBorrowPower(user);

        uint256 hf =
            getHealthFactor(user);

        return (
            collateral,
            debt,
            borrowPower > debt
                ? borrowPower - debt
                : 0,
            hf
        );
    }

    /**
     * ---------------------------------------------------
     * USER POSITION
     * ---------------------------------------------------
     */

    function getUserPosition(
        address user,
        address asset
    )
        external
        view
        returns (
            uint256 supplied,
            uint256 borrowed
        )
    {
        return (
            getUserSupply(
                user,
                asset
            ),
            getUserBorrow(
                user,
                asset
            )
        );
    }

    /**
     * ---------------------------------------------------
     * RESERVE DATA
     * ---------------------------------------------------
     */

    function getReserveData(
        address asset
    )
        external
        view
        returns (
            uint256 supplied,
            uint256 borrowed,
            uint256 supplyAPY,
            uint256 borrowAPY,
            uint256 ltv,
            uint256 liquidationThreshold,
            uint256 liquidityIndex,
            uint256 borrowIndex
        )
    {
        ReserveData memory reserve =
            reserves[asset];

        return (
            reserve.totalSupplied,
            reserve.totalBorrowed,
            reserve.supplyAPY,
            reserve.borrowAPY,
            reserve.ltv,
            reserve.liquidationThreshold,
            reserve.liquidityIndex,
            reserve.borrowIndex
        );
    }
}

